// ── Step 1: Parse request body ──────────────────────────────────
const body = $input.all()[0].json.body;
const apifyToken = body.apify_token;
const target = (body.target || '').trim();
const keywords = Array.isArray(body.keywords) ? body.keywords : [];

// ── Step 2: Build search query ───────────────────────────────────
const extras = keywords.length ? keywords.join(' ') : 'contact email';
const query = `${target} ${extras}`.trim();

// ── Step 3: Apify Google SERP scraper (sync, ~20-30s) ───────────
let rawResults = [];
try {
  rawResults = await $helpers.httpRequest({
    method: 'POST',
    url: `https://api.apify.com/v2/acts/apify~google-search-scraper/run-sync-get-dataset-items?token=${apifyToken}`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      queries: query,
      maxPagesPerQuery: 1,
      resultsPerPage: 10,
      saveHtml: false,
      saveMarkdown: false,
    }),
  });
  if (!Array.isArray(rawResults)) rawResults = [];
} catch (err) {
  console.error('[Search] Apify error:', String(err));
  return [{ json: { _empty: true } }];
}

// ── Step 4: Dedupe by domain + filter by keyword relevance ───────
const kwLower = keywords.map(k => k.toLowerCase());
const seen = new Set();
const output = [];

for (const r of rawResults) {
  const url = r.url || r.canonicalUrl || '';
  if (!url) continue;

  let domain = '';
  try { domain = new URL(url).hostname.replace(/^www\./, ''); }
  catch { domain = url; }

  if (!domain || seen.has(domain)) continue;
  seen.add(domain);

  const text = `${r.title || ''} ${r.description || ''}`.toLowerCase();
  const relevant = kwLower.length === 0 || kwLower.some(k => text.includes(k));
  if (!relevant) continue;

  const company = (r.title || domain).split(/[|\-\u2013\u00b7]/)[0].trim();
  // Pass _body so Apollo/Hunter keys are accessible downstream
  output.push({ json: { url, domain, company, _body: body } });
}

return output.length > 0 ? output : [{ json: { _empty: true } }];

// Skip the empty sentinel produced when Apify finds nothing
const item = $input.item.json;
if (item._empty) return [];

const { company, domain, url } = item;
const body = item._body;
const apolloKey = body.apollo_key;
const hunterKey = body.hunter_key;

// ── Apollo People Search (free — no credits used) ────────────────
let people = [];
try {
  const sr = await $helpers.httpRequest({
    method: 'POST',
    url: 'https://api.apollo.io/api/v1/mixed_people/search',
    headers: { 'Content-Type': 'application/json', 'x-api-key': apolloKey },
    body: JSON.stringify({
      q_keywords: company,
      organization_domains: [domain],
      person_titles: ['owner', 'founder', 'ceo', 'coo', 'director', 'manager', 'president'],
      page: 1,
      per_page: 3,
    }),
  });
  people = sr.people || [];
} catch {
  return [];
}

const leads = [];

for (const person of people.slice(0, 3)) {
  if (!person.id) continue;
  try {
    // ── Apollo People Match (1 credit — reveals email) ────────────
    const mr = await $helpers.httpRequest({
      method: 'POST',
      url: 'https://api.apollo.io/api/v1/people/match',
      headers: { 'Content-Type': 'application/json', 'x-api-key': apolloKey },
      body: JSON.stringify({ id: person.id }),
    });
    const p = mr.person || {};
    if (!p.email) continue;

    // ── Hunter Email Verifier (0.5 credits) ──────────────────────
    const vr = await $helpers.httpRequest({
      method: 'GET',
      url: `https://api.hunter.io/v2/email-verifier?email=${encodeURIComponent(p.email)}&api_key=${hunterKey}`,
    });
    const vd = vr.data || {};

    // Accept: valid, or accept_all with confidence ≥ 80
    const accepted =
      vd.status === 'valid' ||
      (vd.status === 'accept_all' && (vd.score ?? 0) >= 80);
    if (!accepted) continue;

    leads.push({ json: {
      company:      p.organization_name || company,
      contact_name: p.name || person.name || '',
      title:        p.title || person.title || '',
      email:        p.email,
      email_status: vd.status || 'unknown',
      source_url:   url,
    }});
  } catch {
    continue; // skip person on rate-limit or API error
  }
}

return leads;
